{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a topological map compression task. To maximize empty cells (0), we need to find the smallest possible representation of the color adjacency graph that preserves connectivity and adjacency. This requires graph analysis and a layout algorithm.",
  "helpers": [
    {
      "label": "graph_analyzer",
      "instructions": "Analyze the input 50x50 grid to extract two things: 1. A list of all non-zero colors and their connectivity (which colors are adjacent to which). 2. A verification that each color's original cells form a single connected component. Output this as an adjacency list of colors."
    },
    {
      "label": "layout_optimizer",
      "instructions": "Given an adjacency list of colors, find a way to place these colors on a 50x50 grid such that: 1. Each color occupies at least one cell. 2. Two colors are adjacent in the grid if and only if they are adjacent in the list. 3. The number of cells used is minimized to maximize the number of 0 cells. Suggest a compact layout (e.g., a path, a tree, or a small cluster) that satisfies the adjacency constraints."
    },
    {
      "label": "code_generator",
      "instructions": "Write a Python script main.py that reads the 50x50 grid from stdin, processes the adjacency requirements, and outputs a 50x50 grid. The script should implement a robust baseline: it must ensure all colors are present, all adjacencies are preserved, and all colors are connected. A safe approach is to find a spanning tree of the color adjacency graph and lay it out in a snake-like or spiral pattern on the grid to ensure connectivity and adjacency while leaving as many 0s as possible."
    }
  ],
  "synthesis_brief": "Combine the adjacency list from the graph_analyzer with the layout strategy from the layout_optimizer to produce a valid, high-scoring grid. The code_generator will then implement this logic into a complete main.py file that reads the input and prints the resulting grid."
}

